module register_8bit (CLK, CLR, LOAD, D, Q);
input CLK, CLR, LOAD;
input [7:0] D;
output reg [7:0] Q;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge CLR or posedge dbg_halt) begin
    if (CLR)
        Q <= 8'b00000000;
    else if (LOAD)
        Q <= D;
end

endmodule
